import { expectDiagnostics } from "@typespec/compiler/testing";
import { describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";

describe("@entity", () => {
  describe("valid", () => {
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.decorator_entity
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T001.T001_01
    it("model inside Products.<X>.Entities.<Y> namespace", async () => {
      const runner = await Tester.createInstance();
      await runner.compile(`
        namespace Products.MyProduct.Entities.Task;

        @entity
        model Task {
          id: string;
        }
      `);
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T001.T001_02
    it("entity field typed as another @entity model", async () => {
      // An entity field whose type is itself an @entity is a valid pattern —
      // the validator must not reject a model just because one of its field
      // types is also decorated with @entity.
      const runner = await Tester.createInstance();
      await runner.compile(`
        namespace Products.MyProduct.Entities.User {
          @entity
          model User { name: string; }
        }

        namespace Products.MyProduct.Entities.Task {
          using Products.MyProduct.Entities.User;

          @entity
          model Task {
            id: string;
            assignedTo?: User;
          }
        }
      `);
    });
  });

  describe("invalid", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T001.T001_03
    it("model at global scope — no namespace", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @entity
        model Task {
          id: string;
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Products\.<Name>\.Entities\.<Name>/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T001.T001_04
    it("model inside a @component namespace", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @component(#{ type: ComponentType.Service })
        namespace Components.MyApiService {
          @entity
          model Task { id: string; }
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Products\.<Name>\.Entities\.<Name>/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T001.T001_05
    it("model inside a @feature namespace", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        @feature
        namespace Products.MyProduct.Features.MyFeature {
          @entity
          model Task { id: string; }
        }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Products\.<Name>\.Entities\.<Name>/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T001.T001_06
    it("model inside wrong path — missing Entities segment", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        namespace Products.MyProduct.Models.Task;

        @entity
        model Task { id: string; }
      `);
      expectDiagnostics(diagnostics, {
        code: "@a10n/blueprint-typespec/invalid-namespace-prefix",
        message: /Products\.<Name>\.Entities\.<Name>/,
      });
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Decorators.T001.T001_07
    it("duplicate @entity on the same model", async () => {
      const runner = await Tester.createInstance();
      const diagnostics = await runner.diagnose(`
        namespace Products.MyProduct.Entities.Task;

        @entity
        @entity
        model Task {
          id: string;
        }
      `);
      expectDiagnostics(diagnostics, [
        { code: "@a10n/blueprint-typespec/duplicate-decorator", message: /entity/ },
        { code: "@a10n/blueprint-typespec/duplicate-decorator", message: /entity/ },
      ]);
    });
  });
});
